import{_ as t,o,c as i,a0 as a}from"./chunks/framework.jwovEGr5.js";const h=JSON.parse('{"title":"Architecture & Engine","description":"Understand how geoplot-themes bridges the Python geospatial ecosystem with the R rendering engine.","frontmatter":{"title":"Architecture & Engine","description":"Understand how geoplot-themes bridges the Python geospatial ecosystem with the R rendering engine."},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md"}'),r={name:"guide/architecture.md"};function c(n,e,s,d,l,g){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="architecture-engine" tabindex="-1">Architecture &amp; Engine <a class="header-anchor" href="#architecture-engine" aria-label="Permalink to &quot;Architecture &amp; Engine&quot;">​</a></h1><p>The core rendering engine of <code>geoplot-themes</code> is not actually Python—it&#39;s R.</p><p>When you call <code>gpt.plot_map_r()</code>, the package performs the following pipeline:</p><ol><li><strong>Python Validation</strong>: It validates your inputs, file paths, and color codes in Python.</li><li><strong>R Script Generation</strong>: It dynamically generates a temporary R script (<code>.R</code> file) containing customized <code>ggplot2</code> code tailored to your exact specifications.</li><li><strong>Execution</strong>: It spawns an R subprocess using <code>subprocess.run</code>, running the generated script.</li><li><strong>Output</strong>: The R engine reads your shapefiles and rasters using <code>sf</code> and <code>terra</code>, builds the <code>ggplot</code> object, applies the requested theme, and saves a <code>.png</code> directly to your disk.</li></ol><h2 id="required-r-packages" tabindex="-1">Required R Packages <a class="header-anchor" href="#required-r-packages" aria-label="Permalink to &quot;Required R Packages&quot;">​</a></h2><p>For this to work, your system must have R installed and added to your <code>PATH</code>. The package will automatically attempt to install the following CRAN packages if they are missing:</p><ul><li><code>ggplot2</code></li><li><code>sf</code></li><li><code>terra</code></li><li><code>ggspatial</code></li><li><code>ggnewscale</code></li><li><code>ggrepel</code></li><li><code>patchwork</code></li></ul>',7)])])}const u=t(r,[["render",c]]);export{h as __pageData,u as default};
